-- L2 Mock 知识库种子数据，仅用于开发、联调和本地验证。
-- 执行前请先确认 risk_category、risk_details 以及 L2 知识库表已经存在。
-- 本脚本可重复执行：risk_detail_rule 通过 risk_details_id 幂等更新，
-- risk_attack_feature 通过稳定 content_hash 幂等更新。
--
-- 数据设计说明：
-- 1. risk_detail_rule 覆盖当前 31 个风险小类，每个小类一条判定规则。
-- 2. risk_attack_feature 每个小类 3 条特征：2 条 UNSAFE + 1 条 SAFE_EXCEPTION。
-- 3. 特征文本只保留风险识别关键词，不写具体违法、危险或可执行步骤。
-- 4. sync_status/es_sync_status/milvus_sync_status 统一置为 1，表示“模拟已同步到外部索引”。
-- 5. source/creator/updater 使用 mock_l2_seed/codex_mock，便于后续清理或替换正式数据。

SET NAMES utf8mb4;

-- 风险小类判定规则：
-- 规则表是 risk_details 维度的解释性知识，L2 主要用 severity_level 补充日志和路由上下文。
-- 后续 L3 Judge 接入时，可以复用 judge_rule、decision_boundary、unsafe_examples、safe_examples 组装裁决 Prompt。
INSERT INTO `risk_detail_rule` (
